import{_ as e,c as a,o,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Квота OpenAI: лимиты за 3 часа и 24 часа | opencode-mystatus","description":"Научитесь запрашивать лимиты за 3 часа и 24 часа подписки OpenAI ChatGPT. Интерпретируйте основное и вторичное окна, индикаторы прогресса и время сброса. Понимайте механизм ограничения и способ вызова официального API, различия в квоте подписок Plus、Team、Pro, управляйте квотой команды, обрабатывайте проблемы с истечением срока действия Token.","frontmatter":{"title":"Квота OpenAI: лимиты за 3 часа и 24 часа | opencode-mystatus","sidebarTitle":"Квота OpenAI","subtitle":"Квота OpenAI: лимиты за 3 часа и 24 часа","description":"Научитесь запрашивать лимиты за 3 часа и 24 часа подписки OpenAI ChatGPT. Интерпретируйте основное и вторичное окна, индикаторы прогресса и время сброса. Понимайте механизм ограничения и способ вызова официального API, различия в квоте подписок Plus、Team、Pro, управляйте квотой команды, обрабатывайте проблемы с истечением срока действия Token.","tags":["OpenAI","Запрос квоты","API квота"],"prerequisite":["start-quick-start","start-understanding-output"],"order":1},"headers":[],"relativePath":"ru/vbgate/opencode-mystatus/platforms/openai-usage/index.md","filePath":"ru/vbgate/opencode-mystatus/platforms/openai-usage/index.md"}'),l={name:"ru/vbgate/opencode-mystatus/platforms/openai-usage/index.md"};function i(s,t,r,d,p,c){return o(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="запрос-квоты-openai-лимиты-за-3-часа-и-24-часа" tabindex="-1">Запрос квоты OpenAI: лимиты за 3 часа и 24 часа <a class="header-anchor" href="#запрос-квоты-openai-лимиты-за-3-часа-и-24-часа" aria-label="Permalink to &quot;Запрос квоты OpenAI: лимиты за 3 часа и 24 часа&quot;">​</a></h1><h2 id="что-вы-научитесь-делать" tabindex="-1">Что вы научитесь делать <a class="header-anchor" href="#что-вы-научитесь-делать" aria-label="Permalink to &quot;Что вы научитесь делать&quot;">​</a></h2><ul><li>Использовать <code>/mystatus</code> для запроса квоты подписки OpenAI Plus/Team/Pro</li><li>Понимать информацию о лимитах за 3 часа и 24 часа в выводе</li><li>Поймите разницу между основным и вторичным окнами</li><li>Поймите способ обработки при истечении срока действия Token</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><p>У вызовов API OpenAI есть лимиты, после превышения временно ограничивается доступ. Но вы не знаете:</p><ul><li>Сколько осталось квоты?</li><li>Какое окно из 3 часов или 24 часов используется?</li><li>Когда сбросится?</li><li>Почему иногда видите данные обоих окон?</li></ul><p>Если вы не освоите эту информацию вовремя, это может повлиять на ваш прогресс использования ChatGPT для написания кода или проектов.</p><h2 id="когда-использовать-этот-метод" tabindex="-1">Когда использовать этот метод <a class="header-anchor" href="#когда-использовать-этот-метод" aria-label="Permalink to &quot;Когда использовать этот метод&quot;">​</a></h2><p>Когда вы:</p><ul><li>Нужно часто использовать API OpenAI для разработки</li><li>Обнаружили замедление ответа или ограничение</li><li>Хотите понять использование учётной записи команды</li><li>Хотите знать, когда обновится квота</li></ul><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p>У OpenAI есть два окна ограничения для вызовов API:</p><table tabindex="0"><thead><tr><th>Тип окна</th><th>Длительность</th><th>Роль</th></tr></thead><tbody><tr><td><strong>Основное окно</strong>（primary）</td><td>Возвращается сервером OpenAI</td><td>Предотвращение массовых вызовов за короткое время</td></tr><tr><td><strong>Вторичное окно</strong>（secondary）</td><td>Возвращается сервером OpenAI (возможно, не существует)</td><td>Предотвращение долгосрочного превышения</td></tr></tbody></table><p>mystatus будет параллельно запрашивать оба окна, отображая соответственно:</p><ul><li>Процент использованного</li><li>Индикатор прогресса оставшейся квоты</li><li>Время до сброса</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Длительность окна возвращается сервером OpenAI, разные типы подписок (Plus、Team、Pro) могут быть разными.</p></div><h2 id="следуите-за-мнои" tabindex="-1">Следуйте за мной <a class="header-anchor" href="#следуите-за-мнои" aria-label="Permalink to &quot;Следуйте за мной&quot;">​</a></h2><h3 id="шаг-1-выполните-команду-запроса" tabindex="-1">Шаг 1: Выполните команду запроса <a class="header-anchor" href="#шаг-1-выполните-команду-запроса" aria-label="Permalink to &quot;Шаг 1: Выполните команду запроса&quot;">​</a></h3><p>В OpenCode введите <code>/mystatus</code>, система автоматически запросит квоту всех настроенных платформ.</p><p><strong>Что вы должны увидеть</strong>: Включает информацию о квоте платформ OpenAI、智谱 AI、Z.ai、Copilot、Google Cloud и т. д. (зависит от того, какие платформы вы настроили).</p><h3 id="шаг-2-наидите-часть-openai" tabindex="-1">Шаг 2: Найдите часть OpenAI <a class="header-anchor" href="#шаг-2-наидите-часть-openai" aria-label="Permalink to &quot;Шаг 2: Найдите часть OpenAI&quot;">​</a></h3><p>В выводе найдите часть <code>## OpenAI Account Quota</code>.</p><p><strong>Что вы должны видеть</strong>:</p><p>Похожее содержание:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## OpenAI Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3-hour limit</span></span>
<span class="line"><span>███████████████░░░░░░░░░░ 60% remaining</span></span>
<span class="line"><span>Resets in: 2h 30m</span></span></code></pre></div><h3 id="шаг-3-интерпретация-информации-основного-окна" tabindex="-1">Шаг 3: Интерпретация информации основного окна <a class="header-anchor" href="#шаг-3-интерпретация-информации-основного-окна" aria-label="Permalink to &quot;Шаг 3: Интерпретация информации основного окна&quot;">​</a></h3><p><strong>Основное окно</strong>（primary_window）обычно отображает:</p><ul><li><strong>Название окна</strong>: например, <code>3-hour limit</code> или <code>24-hour limit</code></li><li><strong>Индикатор прогресса</strong>: визуально отображает долю оставшейся квоты</li><li><strong>Оставшийся процент</strong>: например, <code>60% remaining</code></li><li><strong>Время сброса</strong>: например, <code>Resets in: 2h 30m</code></li></ul><p><strong>Что вы должны видеть</strong>:</p><ul><li>Название окна отображает длительность (3 часа / 24 часа)</li><li>Чем полнее индикатор прогресса, тем больше осталось; чем пустее, тем быстрее закончится</li><li>Время сброса — это обратный отсчёт, после обнуления квота обновится</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Если вы видите подсказку <code>Limit reached!</code>, это означает, что квота текущего окна использована, нужно ждать сброса.</p></div><h3 id="шаг-4-просмотр-вторичного-окна-если-есть" tabindex="-1">Шаг 4: Просмотр вторичного окна (если есть) <a class="header-anchor" href="#шаг-4-просмотр-вторичного-окна-если-есть" aria-label="Permalink to &quot;Шаг 4: Просмотр вторичного окна (если есть)&quot;">​</a></h3><p>Если OpenAI вернул данные вторичного окна, вы увидите:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>24-hour limit</span></span>
<span class="line"><span>████████████████████████████ 90% remaining</span></span>
<span class="line"><span>Resets in: 20h 45m</span></span></code></pre></div><p><strong>Что вы должны видеть</strong>:</p><ul><li>Вторичное окно отображает квоту другого временного измерения (обычно 24 часа)</li><li>Может быть отличный от основного окна оставшийся процент</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Вторичное окно — это независимый пул квоты, использование основного окна не влияет на вторичное окно, и наоборот.</p></div><h3 id="шаг-5-просмотр-типа-подписки" tabindex="-1">Шаг 5: Просмотр типа подписки <a class="header-anchor" href="#шаг-5-просмотр-типа-подписки" aria-label="Permalink to &quot;Шаг 5: Просмотр типа подписки&quot;">​</a></h3><p>В строке <code>Account</code> можно увидеть тип подписки:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span>                                   ^^^^^</span></span>
<span class="line"><span>                                   Тип подписки</span></span></code></pre></div><p><strong>Общие типы подписок</strong>:</p><ul><li><code>plus</code>：личная подписка Plus</li><li><code>team</code>：подписка команды/организации</li><li><code>pro</code>：подписка Pro</li></ul><p><strong>Что вы должны видеть</strong>:</p><ul><li>Тип вашей подписки отображается в скобках после почты</li><li>Разные типы могут иметь разные лимиты</li></ul><h2 id="контрольная-точка-✅" tabindex="-1">Контрольная точка ✅ <a class="header-anchor" href="#контрольная-точка-✅" aria-label="Permalink to &quot;Контрольная точка ✅&quot;">​</a></h2><p>Проверьте, что вы понимаете:</p><table tabindex="0"><thead><tr><th>Сценарий</th><th>Что вы должны видеть</th></tr></thead><tbody><tr><td>Основное окно осталось 60%</td><td>Индикатор прогресса примерно 60% заполнен, отображается <code>60% remaining</code></td></tr><tr><td>Сброс через 2.5 часа</td><td>Отображается <code>Resets in: 2h 30m</code></td></tr><tr><td>Лимит достигнут</td><td>Отображается <code>Limit reached!</code></td></tr><tr><td>Есть вторичное окно</td><td>Основное и вторичное окна отображают данные по одной строке каждый</td></tr></tbody></table><h2 id="предупреждения-о-ловушках" tabindex="-1">Предупреждения о ловушках <a class="header-anchor" href="#предупреждения-о-ловушках" aria-label="Permalink to &quot;Предупреждения о ловушках&quot;">​</a></h2><h3 id="❌-ошибочная-операция-не-обновлять-после-истечения-срока-деиствия-token" tabindex="-1">❌ Ошибочная операция: не обновлять после истечения срока действия Token <a class="header-anchor" href="#❌-ошибочная-операция-не-обновлять-после-истечения-срока-деиствия-token" aria-label="Permalink to &quot;❌ Ошибочная операция: не обновлять после истечения срока действия Token&quot;">​</a></h3><p><strong>Ошибка</strong>: видите подсказку <code>⚠️ Авторизация OAuth истекла</code> (китайский) или <code>⚠️ OAuth token expired</code> (английский)</p><p><strong>Причина</strong>: OAuth Token истёк (определяется конкретной длительностью сервером), после истечения невозможно запросить квоту.</p><p><strong>Правильное действие</strong>:</p><ol><li>Повторно войдите в OpenAI через OpenCode</li><li>Token автоматически обновится</li><li>Снова выполните <code>/mystatus</code> для запроса</li></ol><h3 id="❌-ошибочная-операция-путаница-основного-и-вторичного-окон" tabindex="-1">❌ Ошибочная операция: путаница основного и вторичного окон <a class="header-anchor" href="#❌-ошибочная-операция-путаница-основного-и-вторичного-окон" aria-label="Permalink to &quot;❌ Ошибочная операция: путаница основного и вторичного окон&quot;">​</a></h3><p><strong>Ошибка</strong>: думали, что есть только одна квота окна, но основное окно использовано, а вторичное всё ещё используется</p><p><strong>Причина</strong>: два окна — это независимые пулы квоты.</p><p><strong>Правильное действие</strong>:</p><ul><li>Следите за временем сброса обоих окон</li><li>Основное окно сбрасывается быстро, вторичное окно сбрасывается медленно</li><li>Разумно распределяйте использование, избегайте длительного превышения одного окна</li></ul><h3 id="❌-ошибочная-операция-игнорирование-id-команднои-учетнои-записи" tabindex="-1">❌ Ошибочная операция: игнорирование ID командной учётной записи <a class="header-anchor" href="#❌-ошибочная-операция-игнорирование-id-команднои-учетнои-записи" aria-label="Permalink to &quot;❌ Ошибочная операция: игнорирование ID командной учётной записи&quot;">​</a></h3><p><strong>Ошибка</strong>: подписка Team отображает не ваше собственное использование</p><p><strong>Причина</strong>: подписке Team нужно передать ID командной учётной записи, иначе может запрашиваться учётная запись по умолчанию.</p><p><strong>Правильное действие</strong>:</p><ul><li>Убедитесь, что вы вошли в правильную командную учётную запись в OpenCode</li><li>В Token автоматически будет включён <code>chatgpt_account_id</code></li></ul><h2 id="итог-урока" tabindex="-1">Итог урока <a class="header-anchor" href="#итог-урока" aria-label="Permalink to &quot;Итог урока&quot;">​</a></h2><p>mystatus запрашивает квоту через вызов официального API OpenAI:</p><ul><li>Поддерживает аутентификацию OAuth (Plus/Team/Pro)</li><li>Отображает основное и вторичное окна (если существуют)</li><li>Индикатор прогресса визуализирует оставшуюся квоту</li><li>Обратный отсчёт отображает время сброса</li><li>Автоматически обнаруживает истечение срока действия Token</li></ul><h2 id="предварительныи-обзор-следующего-урока" tabindex="-1">Предварительный обзор следующего урока <a class="header-anchor" href="#предварительныи-обзор-следующего-урока" aria-label="Permalink to &quot;Предварительный обзор следующего урока&quot;">​</a></h2><blockquote><p>На следующем уроке мы изучим <strong><a href="./../zhipu-usage/">Запрос квоты 智谱 AI и Z.ai</a></strong>。</p><p>Вы узнаете:</p><ul><li>Что такое лимит Token за 5 часов</li><li>Как просмотреть ежемесячную квоту MCP</li><li>Предупреждение при использовании более 80%</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите для просмотра местоположения исходного кода</strong></summary><blockquote><p>Время обновления: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Номер строки</th></tr></thead><tbody><tr><td>Точка входа запроса квоты OpenAI</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L207-L236" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>207-236</td></tr><tr><td>Вызов API OpenAI</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L132-L155" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>132-155</td></tr><tr><td>Форматирование вывода</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L164-L194" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>164-194</td></tr><tr><td>Разбор JWT Token</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L64-L73" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>64-73</td></tr><tr><td>Извлечение почты пользователя</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L78-L81" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>78-81</td></tr><tr><td>Проверка истечения срока действия Token</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L216-L221" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>216-221</td></tr><tr><td>Определение типа OpenAIAuthData</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L28-L33" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>28-33</td></tr></tbody></table><p><strong>Константы</strong>:</p><ul><li><code>OPENAI_USAGE_URL = &quot;https://chatgpt.com/backend-api/wham/usage&quot;</code>：официальный API запроса квоты OpenAI</li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>queryOpenAIUsage(authData)</code>：основная функция запроса квоты OpenAI</li><li><code>fetchOpenAIUsage(accessToken)</code>：вызов API OpenAI</li><li><code>formatOpenAIUsage(data, email)</code>：форматирование вывода</li><li><code>parseJwt(token)</code>：разбор JWT Token (нестандартная реализация библиотеки)</li><li><code>getEmailFromJwt(token)</code>：извлечение почты пользователя из Token</li><li><code>getAccountIdFromJwt(token)</code>：извлечение ID командной учётной записи из Token</li></ul></details>`,71)])])}const b=e(l,[["render",i]]);export{u as __pageData,b as default};
